#!/usr/bin/env node
// tools/perf-baseline.mjs — the ONLY sanctioned writer of tools/perf-baseline.json
// (`pnpm perf:baseline`). Discipline mirrors the harness floor snapshot
// (generate-floor --check/--write): regenerated by this explicit command,
// committed by a human in a reviewed diff — never edited ad hoc (the JSON is
// write-guard-protected), never touched by `update` (seeded). It builds the
// desktop bundle with EXACTLY the build gate's command and measures through the
// SAME lib (tools/lib/bundle-measure.mjs), so gate and baseline can never
// disagree about what a byte is. Human-tuned knobs (ratioCap,
// installerBudgetBytes, comment) survive regeneration; only measured bytes move.
// SOURCE: docs/harness/gates-catalog.md (build gate — gzip ratchet) [corpus: harness/doctrine]
import { existsSync, readFileSync, writeFileSync } from 'node:fs'
import {
  BASELINE_FILE,
  composeBaseline,
  diffBaseline,
  measureDist,
  parseBaseline,
  serializeBaseline,
} from './lib/bundle-measure.mjs'
import { runCmd } from './lib/gate.mjs'

const TAG = 'perf-baseline'
const APP = 'apps/desktop'
const DIST = `${APP}/dist`

function die(msg) {
  console.error(`${TAG}: ${msg}`)
  process.exit(1)
}

if (!existsSync(`${APP}/package.json`)) die(`${APP} not found — nothing to measure`)
if (!existsSync('node_modules')) die('node_modules missing — run pnpm install first')

console.log(`${TAG}: building the desktop bundle (same command as the build gate)…`)
try {
  runCmd('pnpm --filter desktop exec vite build')
} catch (e) {
  die(`vite build failed:\n${(e.stderr?.toString() ?? e.message).slice(-2000)}`)
}
if (!existsSync(DIST)) die(`vite build produced no ${DIST}/`)

const measured = measureDist(DIST)

let prev = null
if (existsSync(BASELINE_FILE)) {
  try {
    prev = parseBaseline(readFileSync(BASELINE_FILE, 'utf8'))
  } catch (e) {
    console.log(
      `${TAG}: existing ${BASELINE_FILE} is unusable (${e.message}) — regenerating from scratch with default ratioCap/installerBudgetBytes`,
    )
  }
}

const next = composeBaseline({ measured, prev })
for (const line of diffBaseline(prev, next)) console.log(`${TAG}: ${line}`)
writeFileSync(BASELINE_FILE, serializeBaseline(next))
console.log(
  `${TAG}: wrote ${BASELINE_FILE} (gzip total ${String(next.gzip.total)} B, ${String(Object.keys(next.gzip.chunks).length)} chunk key(s), ratioCap ${String(next.ratioCap)}) — commit this diff for review; the build gate ratchets against it from the next run`,
)
